package com.inventory.product.dto;
import java.math.BigDecimal;
import jakarta.validation.constraints.*;
public class ProductDto { private Long id; @NotBlank(message="Product name is required") @Size(min=2,max=150,message="Product name must be between 2 and 150 characters") private String name; @Size(max=1000,message="Description cannot exceed 1000 characters") private String description; @NotNull(message="Price is required") @DecimalMin(value="0.0",inclusive=true,message="Price cannot be negative") private BigDecimal price; @NotNull(message="Quantity is required") @Min(value=0,message="Quantity cannot be negative") private Integer quantity; @NotBlank(message="SKU is required") private String sku; private String brand; private String imageUrl; private String status; @NotNull(message="Category ID is required") private Long categoryId; private String categoryName;
 public Long getId(){return id;} public void setId(Long id){this.id=id;} public String getName(){return name;} public void setName(String name){this.name=name;} public String getDescription(){return description;} public void setDescription(String description){this.description=description;} public BigDecimal getPrice(){return price;} public void setPrice(BigDecimal price){this.price=price;} public Integer getQuantity(){return quantity;} public void setQuantity(Integer quantity){this.quantity=quantity;} public String getSku(){return sku;} public void setSku(String sku){this.sku=sku;} public String getBrand(){return brand;} public void setBrand(String brand){this.brand=brand;} public String getImageUrl(){return imageUrl;} public void setImageUrl(String imageUrl){this.imageUrl=imageUrl;} public String getStatus(){return status;} public void setStatus(String status){this.status=status;} public Long getCategoryId(){return categoryId;} public void setCategoryId(Long categoryId){this.categoryId=categoryId;} public String getCategoryName(){return categoryName;} public void setCategoryName(String categoryName){this.categoryName=categoryName;} }
